actionConfiguration.body:
BEGIN;

-- 1. Thử ghi Log (Nếu sai khóa ngoại, nó sẽ báo lỗi ngay tại đây)
INSERT INTO tools_transactions (tool_code, trans_type, quantity, emp_code, urgency_level, machine_id, notes, trans_time)
VALUES (
    {{ this.params.toolCode }}, 
    'EXPORT', 
    {{ this.params.qty }}, 
    {{ this.params.empCode }}, 
    {{ this.params.urgency }}, 
    {{ this.params.machineId }},
    {{ this.params.notes }}, 
    NOW()
);

-- 2. Thực hiện trừ kho
UPDATE tools_catalog 
SET current_qty = current_qty - {{ this.params.qty }}
WHERE tool_code = {{ this.params.toolCode }}
  AND current_qty >= {{ this.params.qty }};

-- 3. Kiểm tra: Nếu UPDATE không thay đổi dòng nào (tức là tồn kho không đủ hoặc không tìm thấy mã), RAISE ERROR để hủy toàn bộ giao dịch
DO $$
BEGIN
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Lỗi: Tồn kho không đủ hoặc không tìm thấy mã vật tư!';
    END IF;
END $$;

COMMIT;
